from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about airports (or related entities) into a single
    fluent complex sentence. Unknown predicates fall back to a generic phrasing.
    """
    if not triples:
        return ""

    def _clean(val: str) -> str:
        """Remove surrounding quotes if present."""
        return val.strip('"').strip("'")

    # Group phrases by subject to avoid repeating the subject
    from collections import defaultdict
    subject_phrases: dict[str, list[str]] = defaultdict(list)

    for t in triples:
        s = t.subject
        p = t.predicate
        o = _clean(t.object)

        # Build predicate‑specific phrase (without repeating the subject)
        if p == "cityServed":
            phrase = f"serves the city of {o}"
        elif p == "location":
            phrase = f"is located in {o}"
        elif p == "country":
            phrase = f"is in {o}"
        elif p == "isPartOf":
            phrase = f"is part of {o}"
        elif p == "elevationAboveTheSeaLevel":
            phrase = f"lies at an elevation of {o} metres above sea level"
        elif p == "elevationAboveTheSeaLevelInFeet":
            phrase = f"lies at an elevation of {o} feet above sea level"
        elif p == "operatingOrganisation":
            phrase = f"is operated by {o}"
        elif p == "runwaySurfaceType":
            phrase = f"has a runway surface of {o}"
        elif p == "runwayLength":
            phrase = f"has a runway length of {o}"
        elif p == "runwayName":
            phrase = f"has a runway named {o}"
        elif p.endswith("RunwayLengthFeet"):
            idx = p.split("Runway")[0].lower()
            phrase = f"has a {idx} runway that is {o} feet long"
        elif p.endswith("RunwayLengthMetre"):
            idx = p.split("Runway")[0].lower()
            phrase = f"has a {idx} runway that is {o} metres long"
        elif p.endswith("RunwayNumber"):
            idx = p.split("Runway")[0].lower()
            phrase = f"has a {idx} runway numbered {o}"
        elif p.endswith("RunwaySurfaceType"):
            idx = p.split("Runway")[0].lower()
            phrase = f"has a {idx} runway surface of {o}"
        else:
            phrase = f"has {p} {o}"

        subject_phrases[s].append(phrase)

    # Build the final complex sentence
    sentences: list[str] = []
    for s, phrases in subject_phrases.items():
        if not phrases:
            continue
        if len(phrases) == 1:
            body = phrases[0]
        else:
            body = ", ".join(phrases[:-1]) + ", and " + phrases[-1]
        sentences.append(f"{s} {body}")

    final = "; ".join(sentences) + "."
    # Capitalise first character
    return final[0].upper() + final[1:]

# EVOLVE-BLOCK-END

